254:                 return new ScramSaslServer(ScramMechanism.forMechanismName(mechanism), props, cbh);
255:             } catch (NoSuchAlgorithmException e) {
256:                 throw new SaslException("Hash algorithm not supported for mechanism " + mechanism, e);
257:             }
258:         }
259: 
260:         @Override
261:         public String[] getMechanismNames(Map<String, ?> props) {
262:             Collection<String> mechanisms = ScramMechanism.mechanismNames();
263:             return mechanisms.toArray(new String[0]);
264:         }
265:     }
266: }
