90: public class SaslServerAuthenticator implements Authenticator {
91:     // GSSAPI limits requests to 64K, but we allow a bit extra for custom SASL mechanisms
92:     static final int MAX_RECEIVE_SIZE = 524288;
93:     private static final Logger LOG = LoggerFactory.getLogger(SaslServerAuthenticator.class);
94: 
95:     /**
96:      * The internal state transitions for initial authentication of a channel on the
97:      * server side are declared in order, starting with {@link #INITIAL_REQUEST} and
98:      * ending in either {@link #COMPLETE} or {@link #FAILED}.
99:      * <p>
100:      * Re-authentication of a channel on the server side starts with the state
101:      * {@link #REAUTH_PROCESS_HANDSHAKE}. It may then flow to
102:      * {@link #REAUTH_BAD_MECHANISM} before a transition to {@link #FAILED} if
103:      * re-authentication is attempted with a mechanism different than the original
104:      * one; otherwise it joins the authentication flow at the {@link #AUTHENTICATE}
105:      * state and likewise ends at either {@link #COMPLETE} or {@link #FAILED}.
106:      */
107:     private enum SaslState {
108:         INITIAL_REQUEST,               // May be GSSAPI token, SaslHandshake or ApiVersions for authentication
109:         HANDSHAKE_OR_VERSIONS_REQUEST, // May be SaslHandshake or ApiVersions
110:         HANDSHAKE_REQUEST,             // After an ApiVersions request, next request must be SaslHandshake
111:         AUTHENTICATE,                  // Authentication tokens (SaslHandshake v1 and above indicate SaslAuthenticate headers)
112:         COMPLETE,                      // Authentication completed successfully
113:         FAILED,                        // Authentication failed
114:         REAUTH_PROCESS_HANDSHAKE,      // Initial state for re-authentication, processes SASL handshake request
115:         REAUTH_BAD_MECHANISM,          // When re-authentication requested with wrong mechanism, generate exception
116:     }
117: 
118:     private final SecurityProtocol securityProtocol;
119:     private final ListenerName listenerName;
120:     private final String connectionId;
121:     private final Map<String, Subject> subjects;
122:     private final TransportLayer transportLayer;
123:     private final List<String> enabledMechanisms;
124:     private final Map<String, ?> configs;
125:     private final KafkaPrincipalBuilder principalBuilder;
126:     private final Map<String, AuthenticateCallbackHandler> callbackHandlers;
127:     private final Map<String, Long> connectionsMaxReauthMsByMechanism;
128:     private final Time time;
129:     private final ReauthInfo reauthInfo;
130:     private final ChannelMetadataRegistry metadataRegistry;
131:     private final Supplier<ApiVersionsResponse> apiVersionSupplier;
132: 
133:     // Current SASL state
134:     private SaslState saslState = SaslState.INITIAL_REQUEST;
135:     // Next SASL state to be set when outgoing writes associated with the current SASL state complete
136:     private SaslState pendingSaslState = null;
137:     // Exception that will be thrown by `authenticate()` when SaslState is set to FAILED after outbound writes complete
138:     private AuthenticationException pendingException = null;
139:     private SaslServer saslServer;
140:     private String saslMechanism;
141: 
142:     // buffers used in `authenticate`
143:     private NetworkReceive netInBuffer;
144:     private Send netOutBuffer;
145:     private Send authenticationFailureSend = null;
146:     // flag indicating if sasl tokens are sent as Kafka SaslAuthenticate request/responses
147:     private boolean enableKafkaSaslAuthenticateHeaders;
148: 
149:     public SaslServerAuthenticator(Map<String, ?> configs,
150:                                    Map<String, AuthenticateCallbackHandler> callbackHandlers,
151:                                    String connectionId,
152:                                    Map<String, Subject> subjects,
153:                                    KerberosShortNamer kerberosNameParser,
154:                                    ListenerName listenerName,
155:                                    SecurityProtocol securityProtocol,
156:                                    TransportLayer transportLayer,
157:                                    Map<String, Long> connectionsMaxReauthMsByMechanism,
158:                                    ChannelMetadataRegistry metadataRegistry,
159:                                    Time time,
160:                                    Supplier<ApiVersionsResponse> apiVersionSupplier) {
161:         this.callbackHandlers = callbackHandlers;
162:         this.connectionId = connectionId;
163:         this.subjects = subjects;
164:         this.listenerName = listenerName;
165:         this.securityProtocol = securityProtocol;
166:         this.enableKafkaSaslAuthenticateHeaders = false;
167:         this.transportLayer = transportLayer;
168:         this.connectionsMaxReauthMsByMechanism = connectionsMaxReauthMsByMechanism;
169:         this.time = time;
170:         this.reauthInfo = new ReauthInfo();
171:         this.metadataRegistry = metadataRegistry;
172:         this.apiVersionSupplier = apiVersionSupplier;
173: 
174:         this.configs = configs;
175:         @SuppressWarnings("unchecked")
176:         List<String> enabledMechanisms = (List<String>) this.configs.get(BrokerSecurityConfigs.SASL_ENABLED_MECHANISMS_CONFIG);
177:         if (enabledMechanisms == null || enabledMechanisms.isEmpty())
178:             throw new IllegalArgumentException("No SASL mechanisms are enabled");
179:         this.enabledMechanisms = new ArrayList<>(new HashSet<>(enabledMechanisms));
180:         for (String mechanism : this.enabledMechanisms) {
181:             if (!callbackHandlers.containsKey(mechanism))
182:                 throw new IllegalArgumentException("Callback handler not specified for SASL mechanism " + mechanism);
183:             if (!subjects.containsKey(mechanism))
184:                 throw new IllegalArgumentException("Subject cannot be null for SASL mechanism " + mechanism);
185:             LOG.trace("{} for mechanism={}: {}", BrokerSecurityConfigs.CONNECTIONS_MAX_REAUTH_MS, mechanism,
186:                     connectionsMaxReauthMsByMechanism.get(mechanism));
187:         }
188: 
189:         // Note that the old principal builder does not support SASL, so we do not need to pass the
190:         // authenticator or the transport layer
191:         this.principalBuilder = ChannelBuilders.createPrincipalBuilder(configs, kerberosNameParser, null);
192:     }
193: 
194:     private void createSaslServer(String mechanism) throws IOException {
195:         this.saslMechanism = mechanism;
196:         Subject subject = subjects.get(mechanism);
197:         final AuthenticateCallbackHandler callbackHandler = callbackHandlers.get(mechanism);
198:         if (mechanism.equals(SaslConfigs.GSSAPI_MECHANISM)) {
199:             saslServer = createSaslKerberosServer(callbackHandler, configs, subject);
200:         } else {
201:             try {
202:                 saslServer = Subject.doAs(subject, (PrivilegedExceptionAction<SaslServer>) () ->
203:                     Sasl.createSaslServer(saslMechanism, "kafka", serverAddress().getHostName(), configs, callbackHandler));
204:                 if (saslServer == null) {
205:                     throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism);
206:                 }
207:             } catch (PrivilegedActionException e) {
208:                 throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism, e.getCause());
209:             }
210:         }
211:     }
212: 
213:     private SaslServer createSaslKerberosServer(final AuthenticateCallbackHandler saslServerCallbackHandler, final Map<String, ?> configs, Subject subject) throws IOException {
214:         // server is using a JAAS-authenticated subject: determine service principal name and hostname from kafka server's subject.
215:         final String servicePrincipal = SaslClientAuthenticator.firstPrincipal(subject);
216:         KerberosName kerberosName;
217:         try {
218:             kerberosName = KerberosName.parse(servicePrincipal);
219:         } catch (IllegalArgumentException e) {
220:             throw new KafkaException("Principal has name with unexpected format " + servicePrincipal);
221:         }
222:         final String servicePrincipalName = kerberosName.serviceName();
223:         final String serviceHostname = kerberosName.hostName();
224: 
225:         LOG.debug("Creating SaslServer for {} with mechanism {}", kerberosName, saslMechanism);
226: 
227:         try {
228:             return Subject.doAs(subject, (PrivilegedExceptionAction<SaslServer>) () ->
229:                     Sasl.createSaslServer(saslMechanism, servicePrincipalName, serviceHostname, configs, saslServerCallbackHandler));
230:         } catch (PrivilegedActionException e) {
231:             throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication", e.getCause());
232:         }
233:     }
234: 
235:     /**
236:      * Evaluates client responses via `SaslServer.evaluateResponse` and returns the issued challenge to the client until
237:      * authentication succeeds or fails.
238:      *
239:      * The messages are sent and received as size delimited bytes that consists of a 4 byte network-ordered size N
240:      * followed by N bytes representing the opaque payload.
241:      */
242:     @SuppressWarnings("fallthrough")
243:     @Override
244:     public void authenticate() throws IOException {
245:         if (saslState != SaslState.REAUTH_PROCESS_HANDSHAKE) {
246:             if (netOutBuffer != null && !flushNetOutBufferAndUpdateInterestOps())
247:                 return;
248: 
249:             if (saslServer != null && saslServer.isComplete()) {
250:                 setSaslState(SaslState.COMPLETE);
251:                 return;
252:             }
253: 
254:             // allocate on heap (as opposed to any socket server memory pool)
255:             if (netInBuffer == null) netInBuffer = new NetworkReceive(MAX_RECEIVE_SIZE, connectionId);
256: 
257:             netInBuffer.readFrom(transportLayer);
258:             if (!netInBuffer.complete())
259:                 return;
260:             netInBuffer.payload().rewind();
261:         }
262:         byte[] clientToken = new byte[netInBuffer.payload().remaining()];
263:         netInBuffer.payload().get(clientToken, 0, clientToken.length);
264:         netInBuffer = null; // reset the networkReceive as we read all the data.
265:         try {
266:             switch (saslState) {
267:                 case REAUTH_PROCESS_HANDSHAKE:
268:                 case HANDSHAKE_OR_VERSIONS_REQUEST:
269:                 case HANDSHAKE_REQUEST:
270:                     handleKafkaRequest(clientToken);
271:                     break;
272:                 case REAUTH_BAD_MECHANISM:
273:                     throw new SaslAuthenticationException(reauthInfo.badMechanismErrorMessage);
274:                 case INITIAL_REQUEST:
275:                     if (handleKafkaRequest(clientToken))
276:                         break;
277:                     // For default GSSAPI, fall through to authenticate using the client token as the first GSSAPI packet.
278:                     // This is required for interoperability with 0.9.0.x clients which do not send handshake request
279:                 case AUTHENTICATE:
280:                     handleSaslToken(clientToken);
281:                     // When the authentication exchange is complete and no more tokens are expected from the client,
282:                     // update SASL state. Current SASL state will be updated when outgoing writes to the client complete.
283:                     if (saslServer.isComplete())
284:                         setSaslState(SaslState.COMPLETE);
285:                     break;
286:                 default:
287:                     break;
288:             }
289:         } catch (AuthenticationException e) {
290:             // Exception will be propagated after response is sent to client
291:             setSaslState(SaslState.FAILED, e);
292:         } catch (Exception e) {
293:             // In the case of IOExceptions and other unexpected exceptions, fail immediately
294:             saslState = SaslState.FAILED;
295:             LOG.debug("Failed during {}: {}", reauthInfo.authenticationOrReauthenticationText(), e.getMessage());
296:             throw e;
297:         }
298:     }
299: 
300:     @Override
301:     public KafkaPrincipal principal() {
302:         Optional<SSLSession> sslSession = transportLayer instanceof SslTransportLayer ?
303:                 Optional.of(((SslTransportLayer) transportLayer).sslSession()) : Optional.empty();
304:         SaslAuthenticationContext context = new SaslAuthenticationContext(saslServer, securityProtocol,
305:                 clientAddress(), listenerName.value(), sslSession);
306:         KafkaPrincipal principal = principalBuilder.build(context);
307:         if (ScramMechanism.isScram(saslMechanism) && Boolean.parseBoolean((String) saslServer.getNegotiatedProperty(ScramLoginModule.TOKEN_AUTH_CONFIG))) {
308:             principal.tokenAuthenticated(true);
309:         }
310:         return principal;
311:     }
312: 
313:     @Override
314:     public Optional<KafkaPrincipalSerde> principalSerde() {
315:         return principalBuilder instanceof KafkaPrincipalSerde ? Optional.of((KafkaPrincipalSerde) principalBuilder) : Optional.empty();
316:     }
317: 
318:     @Override
319:     public boolean complete() {
320:         return saslState == SaslState.COMPLETE;
321:     }
322: 
323:     @Override
324:     public void handleAuthenticationFailure() throws IOException {
325:         sendAuthenticationFailureResponse();
326:     }
