328:     @Override
329:     public void close() throws IOException {
330:         if (principalBuilder instanceof Closeable)
331:             Utils.closeQuietly((Closeable) principalBuilder, "principal builder");
332:         if (saslServer != null)
333:             saslServer.dispose();
334:     }
335: 
336:     @Override
337:     public void reauthenticate(ReauthenticationContext reauthenticationContext) throws IOException {
338:         NetworkReceive saslHandshakeReceive = reauthenticationContext.networkReceive();
339:         if (saslHandshakeReceive == null)
340:             throw new IllegalArgumentException(
341:                     "Invalid saslHandshakeReceive in server-side re-authentication context: null");
342:         SaslServerAuthenticator previousSaslServerAuthenticator = (SaslServerAuthenticator) reauthenticationContext.previousAuthenticator();
343:         reauthInfo.reauthenticating(previousSaslServerAuthenticator.saslMechanism,
344:                 previousSaslServerAuthenticator.principal(), reauthenticationContext.reauthenticationBeginNanos());
345:         previousSaslServerAuthenticator.close();
346:         netInBuffer = saslHandshakeReceive;
347:         LOG.debug("Beginning re-authentication: {}", this);
348:         netInBuffer.payload().rewind();
349:         setSaslState(SaslState.REAUTH_PROCESS_HANDSHAKE);
350:         authenticate();
351:     }
352: 
353:     @Override
354:     public Long serverSessionExpirationTimeNanos() {
355:         return reauthInfo.sessionExpirationTimeNanos;
356:     }
357: 
358:     @Override
359:     public Long reauthenticationLatencyMs() {
360:         return reauthInfo.reauthenticationLatencyMs();
361:     }
362: 
363:     @Override
364:     public boolean connectedClientSupportsReauthentication() {
365:         return reauthInfo.connectedClientSupportsReauthentication;
366:     }
367: 
368:     private void setSaslState(SaslState saslState) {
369:         setSaslState(saslState, null);
370:     }
371: 
372:     private void setSaslState(SaslState saslState, AuthenticationException exception) {
373:         if (netOutBuffer != null && !netOutBuffer.completed()) {
374:             pendingSaslState = saslState;
375:             pendingException = exception;
376:         } else {
377:             this.saslState = saslState;
378:             LOG.debug("Set SASL server state to {} during {}", saslState, reauthInfo.authenticationOrReauthenticationText());
379:             this.pendingSaslState = null;
380:             this.pendingException = null;
381:             if (exception != null)
382:                 throw exception;
383:         }
384:     }
385: 
386:     private boolean flushNetOutBufferAndUpdateInterestOps() throws IOException {
387:         boolean flushedCompletely = flushNetOutBuffer();
388:         if (flushedCompletely) {
389:             transportLayer.removeInterestOps(SelectionKey.OP_WRITE);
390:             if (pendingSaslState != null)
391:                 setSaslState(pendingSaslState, pendingException);
392:         } else
393:             transportLayer.addInterestOps(SelectionKey.OP_WRITE);
394:         return flushedCompletely;
395:     }
396: 
397:     private boolean flushNetOutBuffer() throws IOException {
398:         if (!netOutBuffer.completed())
399:             netOutBuffer.writeTo(transportLayer);
400:         return netOutBuffer.completed();
401:     }
402: 
403:     private InetAddress serverAddress() {
404:         return transportLayer.socketChannel().socket().getLocalAddress();
405:     }
406: 
407:     private InetAddress clientAddress() {
408:         return transportLayer.socketChannel().socket().getInetAddress();
409:     }
410: 
411:     private void handleSaslToken(byte[] clientToken) throws IOException {
412:         if (!enableKafkaSaslAuthenticateHeaders) {
413:             byte[] response = saslServer.evaluateResponse(clientToken);
414:             if (saslServer.isComplete()) {
415:                 reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
416:                 if (reauthInfo.reauthenticating())
417:                     reauthInfo.ensurePrincipalUnchanged(principal());
418:             }
419:             if (response != null) {
420:                 netOutBuffer = ByteBufferSend.sizePrefixed(ByteBuffer.wrap(response));
421:                 flushNetOutBufferAndUpdateInterestOps();
422:             }
423:         } else {
424:             ByteBuffer requestBuffer = ByteBuffer.wrap(clientToken);
425:             RequestHeader header = RequestHeader.parse(requestBuffer);
426:             ApiKeys apiKey = header.apiKey();
427:             short version = header.apiVersion();
428:             RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(),
429:                     KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
430:             RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
431:             if (apiKey != ApiKeys.SASL_AUTHENTICATE) {
432:                 IllegalSaslStateException e = new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL authentication.");
433:                 buildResponseOnAuthenticateFailure(requestContext, requestAndSize.request.getErrorResponse(e));
