435:             }
436:             if (!apiKey.isVersionSupported(version)) {
437:                 // We cannot create an error response if the request version of SaslAuthenticate is not supported
438:                 // This should not normally occur since clients typically check supported versions using ApiVersionsRequest
439:                 throw new UnsupportedVersionException("Version " + version + " is not supported for apiKey " + apiKey);
440:             }
441:             /*
442:              * The client sends multiple SASL_AUTHENTICATE requests, and the client is known
443:              * to support the required version if any one of them indicates it supports that
444:              * version.
445:              */
