492:     private boolean handleKafkaRequest(byte[] requestBytes) throws IOException, AuthenticationException {
493:         boolean isKafkaRequest = false;
494:         String clientMechanism = null;
495:         try {
496:             ByteBuffer requestBuffer = ByteBuffer.wrap(requestBytes);
497:             RequestHeader header = RequestHeader.parse(requestBuffer);
498:             ApiKeys apiKey = header.apiKey();
499: 
500:             // A valid Kafka request header was received. SASL authentication tokens are now expected only
501:             // following a SaslHandshakeRequest since this is not a GSSAPI client token from a Kafka 0.9.0.x client.
502:             if (saslState == SaslState.INITIAL_REQUEST)
503:                 setSaslState(SaslState.HANDSHAKE_OR_VERSIONS_REQUEST);
504:             isKafkaRequest = true;
505: 
506:             // Raise an error prior to parsing if the api cannot be handled at this layer. This avoids
507:             // unnecessary exposure to some of the more complex schema types.
508:             if (apiKey != ApiKeys.API_VERSIONS && apiKey != ApiKeys.SASL_HANDSHAKE)
509:                 throw new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL handshake.");
510: 
511:             LOG.debug("Handling Kafka request {} during {}", apiKey, reauthInfo.authenticationOrReauthenticationText());
512: 
513: 
514:             RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(),
515:                     KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
516:             RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
517:             if (apiKey == ApiKeys.API_VERSIONS)
518:                 handleApiVersionsRequest(requestContext, (ApiVersionsRequest) requestAndSize.request);
519:             else
520:                 clientMechanism = handleHandshakeRequest(requestContext, (SaslHandshakeRequest) requestAndSize.request);
521:         } catch (InvalidRequestException e) {
522:             if (saslState == SaslState.INITIAL_REQUEST) {
523:                 // InvalidRequestException is thrown if the request is not in Kafka format or if the API key
524:                 // is invalid. For compatibility with 0.9.0.x where the first packet is a GSSAPI token
525:                 // starting with 0x60, revert to GSSAPI for both these exceptions.
526:                 if (LOG.isDebugEnabled()) {
527:                     StringBuilder tokenBuilder = new StringBuilder();
528:                     for (byte b : requestBytes) {
529:                         tokenBuilder.append(String.format("%02x", b));
530:                         if (tokenBuilder.length() >= 20)
531:                              break;
532:                     }
533:                     LOG.debug("Received client packet of length {} starting with bytes 0x{}, process as GSSAPI packet", requestBytes.length, tokenBuilder);
534:                 }
535:                 if (enabledMechanisms.contains(SaslConfigs.GSSAPI_MECHANISM)) {
536:                     LOG.debug("First client packet is not a SASL mechanism request, using default mechanism GSSAPI");
537:                     clientMechanism = SaslConfigs.GSSAPI_MECHANISM;
538:                 } else
539:                     throw new UnsupportedSaslMechanismException("Exception handling first SASL packet from client, GSSAPI is not supported by server", e);
540:             } else
541:                 throw e;
542:         }
543:         if (clientMechanism != null && (!reauthInfo.reauthenticating()
544:                 || reauthInfo.saslMechanismUnchanged(clientMechanism))) {
545:             createSaslServer(clientMechanism);
546:             setSaslState(SaslState.AUTHENTICATE);
547:         }
548:         return isKafkaRequest;
549:     }
