574:     private void handleApiVersionsRequest(RequestContext context, ApiVersionsRequest apiVersionsRequest) throws IOException {
575:         if (saslState != SaslState.HANDSHAKE_OR_VERSIONS_REQUEST)
576:             throw new IllegalStateException("Unexpected ApiVersions request received during SASL authentication state " + saslState);
577: 
578:         if (apiVersionsRequest.hasUnsupportedRequestVersion())
579:             sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.UNSUPPORTED_VERSION.exception()));
580:         else if (!apiVersionsRequest.isValid())
581:             sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.INVALID_REQUEST.exception()));
582:         else {
583:             metadataRegistry.registerClientInformation(new ClientInformation(apiVersionsRequest.data().clientSoftwareName(),
584:                 apiVersionsRequest.data().clientSoftwareVersion()));
585:             sendKafkaResponse(context, apiVersionSupplier.get());
586:             setSaslState(SaslState.HANDSHAKE_REQUEST);
587:         }
588:     }
