669:         private long calcCompletionTimesAndReturnSessionLifetimeMs() {
670:             long retvalSessionLifetimeMs = 0L;
671:             long authenticationEndMs = time.milliseconds();
672:             authenticationEndNanos = time.nanoseconds();
673:             Long credentialExpirationMs = (Long) saslServer
674:                     .getNegotiatedProperty(SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY);
675:             Long connectionsMaxReauthMs = connectionsMaxReauthMsByMechanism.get(saslMechanism);
676:             if (credentialExpirationMs != null || connectionsMaxReauthMs != null) {
677:                 if (credentialExpirationMs == null)
678:                     retvalSessionLifetimeMs = zeroIfNegative(connectionsMaxReauthMs);
679:                 else if (connectionsMaxReauthMs == null)
680:                     retvalSessionLifetimeMs = zeroIfNegative(credentialExpirationMs - authenticationEndMs);
681:                 else
682:                     retvalSessionLifetimeMs = zeroIfNegative(
683:                             Math.min(credentialExpirationMs - authenticationEndMs, connectionsMaxReauthMs));
684:                 if (retvalSessionLifetimeMs > 0L)
685:                     sessionExpirationTimeNanos = authenticationEndNanos + 1000 * 1000 * retvalSessionLifetimeMs;
686:             }
687:             if (credentialExpirationMs != null) {
688:                 if (sessionExpirationTimeNanos != null)
689:                     LOG.debug(
690:                             "Authentication complete; session max lifetime from broker config={} ms, credential expiration={} ({} ms); session expiration = {} ({} ms), sending {} ms to client",
691:                             connectionsMaxReauthMs, new Date(credentialExpirationMs),
692:                             credentialExpirationMs - authenticationEndMs,
693:                             new Date(authenticationEndMs + retvalSessionLifetimeMs), retvalSessionLifetimeMs,
694:                             retvalSessionLifetimeMs);
695:                 else
696:                     LOG.debug(
697:                             "Authentication complete; session max lifetime from broker config={} ms, credential expiration={} ({} ms); no session expiration, sending 0 ms to client",
698:                             connectionsMaxReauthMs, new Date(credentialExpirationMs),
699:                             credentialExpirationMs - authenticationEndMs);
700:             } else {
701:                 if (sessionExpirationTimeNanos != null)
702:                     LOG.debug(
703:                             "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; session expiration = {} ({} ms), sending {} ms to client",
704:                             connectionsMaxReauthMs, new Date(authenticationEndMs + retvalSessionLifetimeMs),
705:                             retvalSessionLifetimeMs, retvalSessionLifetimeMs);
706:                 else
707:                     LOG.debug(
708:                             "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; no session expiration, sending 0 ms to client",
709:                             connectionsMaxReauthMs);
710:             }
711:             return retvalSessionLifetimeMs;
712:         }
713: 
714:         public Long reauthenticationLatencyMs() {
715:             if (!reauthenticating())
716:                 return null;
717:             // record at least 1 ms if there is some latency
718:             long latencyNanos = authenticationEndNanos - reauthenticationBeginNanos;
719:             return latencyNanos == 0L ? 0L : Math.max(1L, Math.round(latencyNanos / 1000.0 / 1000.0));
720:         }
721: 
722:         private long zeroIfNegative(long value) {
723:             return Math.max(0L, value);
724:         }        
725:     }
