   217→    private SaslServer createSaslKerberosServer(final AuthenticateCallbackHandler saslServerCallbackHandler, final Map<String, ?> configs, Subject subject) throws IOException {
   218→        // server is using a JAAS-authenticated subject: determine service principal name and hostname from kafka server's subject.
   219→        final String servicePrincipal = SaslClientAuthenticator.firstPrincipal(subject);
   220→        KerberosName kerberosName;
   221→        try {
   222→            kerberosName = KerberosName.parse(servicePrincipal);
   223→        } catch (IllegalArgumentException e) {
   224→            throw new KafkaException("Principal has name with unexpected format " + servicePrincipal);
   225→        }
   226→        final String servicePrincipalName = kerberosName.serviceName();
   227→        final String serviceHostname = kerberosName.hostName();
   228→
   229→        LOG.debug("Creating SaslServer for {} with mechanism {}", kerberosName, saslMechanism);
   230→
   231→        try {
   232→            return Subject.doAs(subject, (PrivilegedExceptionAction<SaslServer>) () ->
   233→                    Sasl.createSaslServer(saslMechanism, servicePrincipalName, serviceHostname, configs, saslServerCallbackHandler));
   234→        } catch (PrivilegedActionException e) {
   235→            throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication", e.getCause());
   236→        }
   237→    }
