   239→    /**
   240→     * Evaluates client responses via `SaslServer.evaluateResponse` and returns the issued challenge to the client until
   241→     * authentication succeeds or fails.
   242→     *
   243→     * The messages are sent and received as size delimited bytes that consists of a 4 byte network-ordered size N
   244→     * followed by N bytes representing the opaque payload.
   245→     */
   246→    @SuppressWarnings("fallthrough")
   247→    @Override
   248→    public void authenticate() throws IOException {
   249→        if (saslState != SaslState.REAUTH_PROCESS_HANDSHAKE) {
   250→            if (netOutBuffer != null && !flushNetOutBufferAndUpdateInterestOps())
   251→                return;
   252→
   253→            if (saslServer != null && saslServer.isComplete()) {
   254→                setSaslState(SaslState.COMPLETE);
   255→                return;
   256→            }
   257→
   258→            // allocate on heap (as opposed to any socket server memory pool)
   259→            if (netInBuffer == null) netInBuffer = new NetworkReceive(saslAuthRequestMaxReceiveSize, connectionId);
   260→
   261→            try {
   262→                netInBuffer.readFrom(transportLayer);
   263→            } catch (InvalidReceiveException e) {
   264→                throw new SaslAuthenticationException("Failing SASL authentication due to invalid receive size", e);
   265→            }
   266→            if (!netInBuffer.complete())
   267→                return;
   268→            netInBuffer.payload().rewind();
   269→        }
   270→        byte[] clientToken = new byte[netInBuffer.payload().remaining()];
   271→        netInBuffer.payload().get(clientToken, 0, clientToken.length);
   272→        netInBuffer = null; // reset the networkReceive as we read all the data.
   273→        try {
   274→            switch (saslState) {
   275→                case REAUTH_PROCESS_HANDSHAKE:
   276→                case HANDSHAKE_OR_VERSIONS_REQUEST:
   277→                case HANDSHAKE_REQUEST:
   278→                    handleKafkaRequest(clientToken);
   279→                    break;
   280→                case REAUTH_BAD_MECHANISM:
   281→                    throw new SaslAuthenticationException(reauthInfo.badMechanismErrorMessage);
   282→                case INITIAL_REQUEST:
   283→                    if (handleKafkaRequest(clientToken))
   284→                        break;
   285→                    // For default GSSAPI, fall through to authenticate using the client token as the first GSSAPI packet.
   286→                    // This is required for interoperability with 0.9.0.x clients which do not send handshake request
   287→                case AUTHENTICATE:
   288→                    handleSaslToken(clientToken);
   289→                    // When the authentication exchange is complete and no more tokens are expected from the client,
   290→                    // update SASL state. Current SASL state will be updated when outgoing writes to the client complete.
   291→                    if (saslServer.isComplete())
   292→                        setSaslState(SaslState.COMPLETE);
   293→                    break;
   294→                default:
   295→                    break;
   296→            }
   297→        } catch (AuthenticationException e) {
   298→            // Exception will be propagated after response is sent to client
   299→            setSaslState(SaslState.FAILED, e);
   300→        } catch (Exception e) {
   301→            // In the case of IOExceptions and other unexpected exceptions, fail immediately
   302→            saslState = SaslState.FAILED;
   303→            LOG.debug("Failed during {}: {}", reauthInfo.authenticationOrReauthenticationText(), e.getMessage());
   304→            throw e;
   305→        }
   306→    }
