   380→    private void setSaslState(SaslState saslState, AuthenticationException exception) {
   381→        if (netOutBuffer != null && !netOutBuffer.completed()) {
   382→            pendingSaslState = saslState;
   383→            pendingException = exception;
   384→        } else {
   385→            this.saslState = saslState;
   386→            LOG.debug("Set SASL server state to {} during {}", saslState, reauthInfo.authenticationOrReauthenticationText());
   387→            this.pendingSaslState = null;
   388→            this.pendingException = null;
   389→            if (exception != null)
   390→                throw exception;
   391→        }
   392→    }
