   394→    private boolean flushNetOutBufferAndUpdateInterestOps() throws IOException {
   395→        boolean flushedCompletely = flushNetOutBuffer();
   396→        if (flushedCompletely) {
   397→            transportLayer.removeInterestOps(SelectionKey.OP_WRITE);
   398→            if (pendingSaslState != null)
   399→                setSaslState(pendingSaslState, pendingException);
   400→        } else
   401→            transportLayer.addInterestOps(SelectionKey.OP_WRITE);
   402→        return flushedCompletely;
   403→    }
   404→
   405→    private boolean flushNetOutBuffer() throws IOException {
   406→        if (!netOutBuffer.completed())
   407→            netOutBuffer.writeTo(transportLayer);
   408→        return netOutBuffer.completed();
   409→    }
