   423→    private void handleSaslToken(byte[] clientToken) throws IOException {
   424→        if (!enableKafkaSaslAuthenticateHeaders) {
   425→            byte[] response = saslServer.evaluateResponse(clientToken);
   426→            if (saslServer.isComplete()) {
   427→                reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   428→                if (reauthInfo.reauthenticating())
   429→                    reauthInfo.ensurePrincipalUnchanged(principal());
   430→            }
   431→            if (response != null) {
   432→                netOutBuffer = ByteBufferSend.sizePrefixed(ByteBuffer.wrap(response));
   433→                flushNetOutBufferAndUpdateInterestOps();
   434→            }
   435→        } else {
   436→            ByteBuffer requestBuffer = ByteBuffer.wrap(clientToken);
   437→            RequestHeader header = RequestHeader.parse(requestBuffer);
   438→            ApiKeys apiKey = header.apiKey();
   439→            short version = header.apiVersion();
   440→            RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
   441→                    KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
   442→            RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
   443→            if (apiKey != ApiKeys.SASL_AUTHENTICATE) {
   444→                IllegalSaslStateException e = new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL authentication.");
   445→                buildResponseOnAuthenticateFailure(requestContext, requestAndSize.request.getErrorResponse(e));
   446→                throw e;
   447→            }
   448→            if (!apiKey.isVersionSupported(version)) {
   449→                // We cannot create an error response if the request version of SaslAuthenticate is not supported
   450→                // This should not normally occur since clients typically check supported versions using ApiVersionsRequest
   451→                throw new UnsupportedVersionException("Version " + version + " is not supported for apiKey " + apiKey);
   452→            }
   453→            /*
   454→             * The client sends multiple SASL_AUTHENTICATE requests, and the client is known
   455→             * to support the required version if any one of them indicates it supports that
   456→             * version.
   457→             */
   458→            if (!reauthInfo.connectedClientSupportsReauthentication)
   459→                reauthInfo.connectedClientSupportsReauthentication = version > 0;
   460→            SaslAuthenticateRequest saslAuthenticateRequest = (SaslAuthenticateRequest) requestAndSize.request;
   461→
   462→            try {
   463→                byte[] responseToken = saslServer.evaluateResponse(
   464→                        Utils.copyArray(saslAuthenticateRequest.data().authBytes()));
   465→                if (reauthInfo.reauthenticating() && saslServer.isComplete())
   466→                    reauthInfo.ensurePrincipalUnchanged(principal());
   467→                // For versions with SASL_AUTHENTICATE header, send a response to SASL_AUTHENTICATE request even if token is empty.
   468→                byte[] responseBytes = responseToken == null ? new byte[0] : responseToken;
   469→                long sessionLifetimeMs = !saslServer.isComplete() ? 0L
   470→                        : reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   471→                sendKafkaResponse(requestContext, new SaslAuthenticateResponse(
   472→                        new SaslAuthenticateResponseData()
   473→                        .setErrorCode(Errors.NONE.code())
   474→                        .setAuthBytes(responseBytes)
   475→                        .setSessionLifetimeMs(sessionLifetimeMs)));
   476→            } catch (SaslAuthenticationException e) {
   477→                buildResponseOnAuthenticateFailure(requestContext,
   478→                        new SaslAuthenticateResponse(
   479→                                new SaslAuthenticateResponseData()
   480→                                .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   481→                                .setErrorMessage(e.getMessage())));
   482→                throw e;
   483→            } catch (SaslException e) {
   484→                KerberosError kerberosError = KerberosError.fromException(e);
   485→                if (kerberosError != null && kerberosError.retriable()) {
   486→                    // Handle retriable Kerberos exceptions as I/O exceptions rather than authentication exceptions
   487→                    throw e;
   488→                } else {
   489→                    // DO NOT include error message from the `SaslException` in the client response since it may
   490→                    // contain sensitive data like the existence of the user.
   491→                    String errorMessage = "Authentication failed during "
   492→                            + reauthInfo.authenticationOrReauthenticationText()
   493→                            + " due to invalid credentials with SASL mechanism " + saslMechanism;
   494→                    buildResponseOnAuthenticateFailure(requestContext, new SaslAuthenticateResponse(
   495→                            new SaslAuthenticateResponseData()
   496→                            .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   497→                            .setErrorMessage(errorMessage)));
   498→                    throw new SaslAuthenticationException(errorMessage, e);
   499→                }
   500→            }
   501→        }
   502→    }
   503→
   504→    private boolean handleKafkaRequest(byte[] requestBytes) throws IOException, AuthenticationException {
   505→        boolean isKafkaRequest = false;
   506→        String clientMechanism = null;
   507→        try {
   508→            ByteBuffer requestBuffer = ByteBuffer.wrap(requestBytes);
   509→            RequestHeader header = RequestHeader.parse(requestBuffer);
   510→            ApiKeys apiKey = header.apiKey();
   511→
   512→            // A valid Kafka request header was received. SASL authentication tokens are now expected only
   513→            // following a SaslHandshakeRequest since this is not a GSSAPI client token from a Kafka 0.9.0.x client.
   514→            if (saslState == SaslState.INITIAL_REQUEST)
   515→                setSaslState(SaslState.HANDSHAKE_OR_VERSIONS_REQUEST);
   516→            isKafkaRequest = true;
   517→
   518→            // Raise an error prior to parsing if the api cannot be handled at this layer. This avoids
   519→            // unnecessary exposure to some of the more complex schema types.
   520→            if (apiKey != ApiKeys.API_VERSIONS && apiKey != ApiKeys.SASL_HANDSHAKE)
   521→                throw new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL handshake.");
   522→
   523→            LOG.debug("Handling Kafka request {} during {}", apiKey, reauthInfo.authenticationOrReauthenticationText());
   524→
   525→
   526→            RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
   527→                    KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
   528→            RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
   529→            if (apiKey == ApiKeys.API_VERSIONS)
   530→                handleApiVersionsRequest(requestContext, (ApiVersionsRequest) requestAndSize.request);
   531→            else
   532→                clientMechanism = handleHandshakeRequest(requestContext, (SaslHandshakeRequest) requestAndSize.request);
   533→        } catch (InvalidRequestException e) {
   534→            if (saslState == SaslState.INITIAL_REQUEST) {
   535→                // InvalidRequestException is thrown if the request is not in Kafka format or if the API key
   536→                // is invalid. For compatibility with 0.9.0.x where the first packet is a GSSAPI token
   537→                // starting with 0x60, revert to GSSAPI for both these exceptions.
   538→                if (LOG.isDebugEnabled()) {
   539→                    StringBuilder tokenBuilder = new StringBuilder();
   540→                    for (byte b : requestBytes) {
   541→                        tokenBuilder.append(String.format("%02x", b));
   542→                        if (tokenBuilder.length() >= 20)
   543→                             break;
   544→                    }
   545→                    LOG.debug("Received client packet of length {} starting with bytes 0x{}, process as GSSAPI packet", requestBytes.length, tokenBuilder);
   546→                }
   547→                if (enabledMechanisms.contains(SaslConfigs.GSSAPI_MECHANISM)) {
   548→                    LOG.debug("First client packet is not a SASL mechanism request, using default mechanism GSSAPI");
   549→                    clientMechanism = SaslConfigs.GSSAPI_MECHANISM;
   550→                } else
   551→                    throw new UnsupportedSaslMechanismException("Exception handling first SASL packet from client, GSSAPI is not supported by server", e);
   552→            } else
   553→                throw e;
   554→        }
   555→        if (clientMechanism != null && (!reauthInfo.reauthenticating()
   556→                || reauthInfo.saslMechanismUnchanged(clientMechanism))) {
   557→            createSaslServer(clientMechanism);
   558→            setSaslState(SaslState.AUTHENTICATE);
   559→        }
   560→        return isKafkaRequest;
   561→    }
   562→
   563→    private String handleHandshakeRequest(RequestContext context, SaslHandshakeRequest handshakeRequest) throws IOException, UnsupportedSaslMechanismException {
   564→        String clientMechanism = handshakeRequest.data().mechanism();
   565→        short version = context.header.apiVersion();
   566→        if (version >= 1)
   567→            this.enableKafkaSaslAuthenticateHeaders(true);
   568→        if (enabledMechanisms.contains(clientMechanism)) {
   569→            LOG.debug("Using SASL mechanism '{}' provided by client", clientMechanism);
   570→            sendKafkaResponse(context, new SaslHandshakeResponse(
   571→                    new SaslHandshakeResponseData().setErrorCode(Errors.NONE.code()).setMechanisms(enabledMechanisms)));
   572→            return clientMechanism;
   573→        } else {
   574→            LOG.debug("SASL mechanism '{}' requested by client is not supported", clientMechanism);
   575→            buildResponseOnAuthenticateFailure(context, new SaslHandshakeResponse(
   576→                    new SaslHandshakeResponseData().setErrorCode(Errors.UNSUPPORTED_SASL_MECHANISM.code()).setMechanisms(enabledMechanisms)));
   577→            throw new UnsupportedSaslMechanismException("Unsupported SASL mechanism " + clientMechanism);
   578→        }
   579→    }
