   629→    /**
   630→     * Information related to re-authentication
   631→     */
   632→    private class ReauthInfo {
   633→        public String previousSaslMechanism;
   634→        public KafkaPrincipal previousKafkaPrincipal;
   635→        public long reauthenticationBeginNanos;
   636→        public Long sessionExpirationTimeNanos;
   637→        public boolean connectedClientSupportsReauthentication;
   638→        public long authenticationEndNanos;
   639→        public String badMechanismErrorMessage;
   640→
   641→        public void reauthenticating(String previousSaslMechanism, KafkaPrincipal previousKafkaPrincipal,
   642→                long reauthenticationBeginNanos) {
   643→            this.previousSaslMechanism = Objects.requireNonNull(previousSaslMechanism);
   644→            this.previousKafkaPrincipal = Objects.requireNonNull(previousKafkaPrincipal);
   645→            this.reauthenticationBeginNanos = reauthenticationBeginNanos;
   646→        }
   647→
   648→        public boolean reauthenticating() {
   649→            return previousSaslMechanism != null;
   650→        }
   651→
   652→        public String authenticationOrReauthenticationText() {
   653→            return reauthenticating() ? "re-authentication" : "authentication";
   654→        }
   655→
   656→        public void ensurePrincipalUnchanged(KafkaPrincipal reauthenticatedKafkaPrincipal) throws SaslAuthenticationException {
   657→            if (!previousKafkaPrincipal.equals(reauthenticatedKafkaPrincipal)) {
   658→                throw new SaslAuthenticationException(String.format(
   659→                        "Cannot change principals during re-authentication from %s.%s: %s.%s",
   660→                        previousKafkaPrincipal.getPrincipalType(), previousKafkaPrincipal.getName(),
   661→                        reauthenticatedKafkaPrincipal.getPrincipalType(), reauthenticatedKafkaPrincipal.getName()));
   662→            }
   663→        }
   664→
   665→        /*
   666→         * We define the REAUTH_BAD_MECHANISM state because the failed re-authentication
   667→         * metric does not get updated if we send back an error immediately upon the
   668→         * start of re-authentication.
   669→         */
   670→        public boolean saslMechanismUnchanged(String clientMechanism) {
   671→            if (previousSaslMechanism.equals(clientMechanism))
   672→                return true;
   673→            badMechanismErrorMessage = String.format(
   674→                    "SASL mechanism '%s' requested by client is not supported for re-authentication of mechanism '%s'",
   675→                    clientMechanism, previousSaslMechanism);
   676→            LOG.debug(badMechanismErrorMessage);
   677→            setSaslState(SaslState.REAUTH_BAD_MECHANISM);
   678→            return false;
   679→        }
   680→
   681→        private long calcCompletionTimesAndReturnSessionLifetimeMs() {
   682→            long retvalSessionLifetimeMs = 0L;
   683→            long authenticationEndMs = time.milliseconds();
   684→            authenticationEndNanos = time.nanoseconds();
   685→            Long credentialExpirationMs = (Long) saslServer
   686→                    .getNegotiatedProperty(SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY);
   687→            Long connectionsMaxReauthMs = connectionsMaxReauthMsByMechanism.get(saslMechanism);
   688→            boolean maxReauthSet = connectionsMaxReauthMs != null && connectionsMaxReauthMs > 0;
   689→
   690→            if (credentialExpirationMs != null || maxReauthSet) {
   691→                if (credentialExpirationMs == null)
   692→                    retvalSessionLifetimeMs = zeroIfNegative(connectionsMaxReauthMs);
   693→                else if (!maxReauthSet)
   694→                    retvalSessionLifetimeMs = zeroIfNegative(credentialExpirationMs - authenticationEndMs);
   695→                else
   696→                    retvalSessionLifetimeMs = zeroIfNegative(Math.min(credentialExpirationMs - authenticationEndMs, connectionsMaxReauthMs));
   697→
   698→                sessionExpirationTimeNanos = authenticationEndNanos + 1000 * 1000 * retvalSessionLifetimeMs;
   699→            }
   700→
   701→            if (credentialExpirationMs != null) {
   702→                LOG.debug(
   703→                        "Authentication complete; session max lifetime from broker config={} ms, credential expiration={} ({} ms); session expiration = {} ({} ms), sending {} ms to client",
   704→                        connectionsMaxReauthMs, new Date(credentialExpirationMs),
   705→                        credentialExpirationMs - authenticationEndMs,
