18: 
19: import java.util.concurrent.ConcurrentHashMap;
20: 
21: public class CredentialCache {
22: 
23:     private final ConcurrentHashMap<String, Cache<?>> cacheMap = new ConcurrentHashMap<>();
24: 
25:     public <C> Cache<C> createCache(String mechanism, Class<C> credentialClass) {
26:         Cache<C> cache = new Cache<>(credentialClass);
27:         @SuppressWarnings("unchecked")
28:         Cache<C> oldCache = (Cache<C>) cacheMap.putIfAbsent(mechanism, cache);
29:         return oldCache == null ? cache : oldCache;
30:     }
31: 
32:     @SuppressWarnings("unchecked")
33:     public <C> Cache<C> cache(String mechanism, Class<C> credentialClass) {
34:         Cache<?> cache = cacheMap.get(mechanism);
35:         if (cache != null) {
36:             if (cache.credentialClass() != credentialClass)
37:                 throw new IllegalArgumentException("Invalid credential class " + credentialClass + ", expected " + cache.credentialClass());
38:             return (Cache<C>) cache;
39:         } else
40:             return null;
41:     }
42: 
43:     public static class Cache<C> {
44:         private final Class<C> credentialClass;
45:         private final ConcurrentHashMap<String, C> credentials;
46: 
47:         public Cache(Class<C> credentialClass) {
48:             this.credentialClass = credentialClass;
49:             this.credentials = new ConcurrentHashMap<>();
50:         }
51: 
