310:         SaslAuthenticationContext context = new SaslAuthenticationContext(saslServer, securityProtocol,
311:                 clientAddress(), listenerName.value(), sslSession);
312:         KafkaPrincipal principal = principalBuilder.build(context);
313:         if (ScramMechanism.isScram(saslMechanism) && Boolean.parseBoolean((String) saslServer.getNegotiatedProperty(ScramLoginModule.TOKEN_AUTH_CONFIG))) {
314:             principal.tokenAuthenticated(true);
